#nullable enable // autogenerated

using System;
using MukioI18n;
using MVZ2.Managers;
using MVZ2.Options;
using MVZ2Logic.Options;
using Newtonsoft.Json.Linq;
using PVZEngine;
using UnityEngine;

namespace MVZ2.Cameras
{
    [ExecuteAlways]
    public class ResolutionManager : MonoBehaviour
    {
        public void SetResolution(int width, int height)
        {
            Screen.SetResolution(width, height, Screen.fullScreenMode);
        }
        public void SetResolution(Resolution resolution)
        {
            SetResolution(resolution.width, resolution.height);
        }
        public Resolution[] GetResolutions()
        {
            return Screen.resolutions;
        }
        public Resolution GetCurrentResolution()
        {
            return new Resolution()
            {
                width = Screen.width,
                height = Screen.height
            };
        }
        private void Awake()
        {
            OptionsManager.OnOptionChangedBool += OnOptionChangedBoolCallback;
        }
        private void OnEnable()
        {
            Check();
        }
        private void OnDisable()
        {
            lastWidth = 0;
            lastHeight = 0;
        }
        private void Update()
        {
            Check();
        }
        private void OnOptionChangedBoolCallback(NamespaceID id, bool value)
        {
            if (id == LogicOptionItemID.fullscreen)
            {
                Screen.fullScreen = value;
            }
        }
        private void Check()
        {
            if (lastWidth != Screen.width || lastHeight != Screen.height)
            {
                lastWidth = Screen.width;
                lastHeight = Screen.height;
                OnResolutionChanged?.Invoke(lastWidth, lastHeight);
            }
        }
        public static event Action<int, int>? OnResolutionChanged;

        private int lastWidth;
        private int lastHeight;
    }
}
